// MOD13Q1: Terra MODIS Vegetation Indices 16-Day 250m
// Load MODIS NDVI collection
var modisNDVI = ee.ImageCollection('MODIS/061/MOD13Q1');

// Define region of interest (Beijing area)
var roi = ee.Geometry.Rectangle([115.7, 39.4, 117.4, 41.0]);

// Filter by date and region
var filtered = modisNDVI
  .filterDate('2020-06-01', '2020-09-30')
  .filterBounds(roi)
  .select('NDVI');

// Apply scale factor (multiply by 0.0001)
var ndvi = filtered.map(function(img) {
  return img.multiply(0.0001).rename('NDVI');
});

// Compute mean NDVI
var ndviMean = ndvi.mean();

// NDVI color palette
var ndviPalette = ['#ce7e45', '#df923d', '#f1b555', '#fcd163', '#99b718',
  '#74a901', '#66a000', '#529400', '#3e8601', '#207401', '#056201',
  '#004c00', '#023b01', '#012e01', '#011d01', '#011301'];

// Add layer to map
Map.addLayer(ndviMean, {min: 0, max: 1, palette: ndviPalette}, 'Mean NDVI');

// Create time series chart
var ndviChart = ui.Chart.image.series({
  imageCollection: ndvi,
  region: roi,
  reducer: ee.Reducer.mean(),
  scale: 250,
  xProperty: 'system:time_start'
});
ndviChart.setOptions({
  title: 'MOD13Q1 NDVI Time Series',
  vAxis: {title: 'NDVI'},
  hAxis: {title: 'Date'},
  lineWidth: 2,
  pointSize: 4
});
print(ndviChart);

