// MOD09GA: Terra MODIS Surface Reflectance Daily
var modisSR = ee.ImageCollection('MODIS/061/MOD09GA');

var roi = ee.Geometry.Rectangle([116.0, 39.5, 117.0, 40.5]);

// Filter for summer 2020
var filtered = modisSR
  .filterDate('2020-07-01', '2020-07-31')
  .filterBounds(roi);

// Apply scale factor
var sr = filtered.map(function(img) {
  return img.multiply(0.0001);
});

// True color composite (R=Band1, G=Band4, B=Band3)
var trueColor = sr.select(['sur_refl_b01', 'sur_refl_b04', 'sur_refl_b03']);

Map.addLayer(trueColor.median(), {min: 0, max: 0.3}, 'True Color Composite');

// False color composite (R=Band2, G=Band1, B=Band4)
var falseColor = sr.select(['sur_refl_b02', 'sur_refl_b01', 'sur_refl_b04']);
Map.addLayer(falseColor.median(), {min: 0, max: 0.5}, 'False Color (NIR-Red-Green)');

// NDVI from surface reflectance
var srImage = sr.median();
var ndvi = srImage.normalizedDifference(['sur_refl_b02', 'sur_refl_b01']).rename('NDVI');
Map.addLayer(ndvi, {min: 0, max: 1, palette: ['red', 'yellow', 'green']}, 'NDVI from SR');

// Chart
var chart = ui.Chart.image.series({
  imageCollection: sr.select('sur_refl_b01').map(function(img) {
    return img.multiply(0.0001);
  }),
  region: roi,
  reducer: ee.Reducer.mean(),
  scale: 500,
  xProperty: 'system:time_start'
});
chart.setOptions({title: 'MOD09GA Red Reflectance', vAxis: {title: 'Reflectance'}});
print(chart);

